import React from 'react';
import {
  CDropdown,
  CDropdownToggle,
  CDropdownMenu,
  CDropdownItem,
  CDropdownDivider,
} from '@coreui/react';
import CIcon from '@coreui/icons-react';
import {
  cilUser,
  cilSettings,
  cilAccountLogout,
} from '@coreui/icons';

const ProfileDropdown = () => {
  return (
    <CDropdown variant="nav-item" className="profile-dropdown">
      <CDropdownToggle className="p-0 border-0 bg-transparent" caret={false}>
        <img
          src="https://ui-avatars.com/api/?name=Dheeraj+Khanna"
          alt="User"
          className="rounded-circle"
          width="36"
          height="36"
          style={{ objectFit: 'cover', cursor: 'pointer' }}
        />
      </CDropdownToggle>

      <CDropdownMenu className="pt-0" placement="bottom-end">
        <CDropdownItem href="#">
          <CIcon icon={cilUser} className="me-2" />
          Profile
        </CDropdownItem>
        <CDropdownItem href="#">
          <CIcon icon={cilSettings} className="me-2" />
          Settings
        </CDropdownItem>
        <CDropdownDivider />
        <CDropdownItem href="#">
          <CIcon icon={cilAccountLogout} className="me-2" />
          Logout
        </CDropdownItem>
      </CDropdownMenu>
    </CDropdown>
  );
};

export default ProfileDropdown;
